class Task(val name: String, var isCompleted: Boolean = false) { fun complete() { isCompleted = true; println("Task $name marked as complete.") } } class TaskManager { private val tasks = mutableListOf<Task>(); fun addTask(name: String) { val task = Task(name); tasks.add(task); println("Added: $name") } fun listTasks() { println("Current Tasks:"); if (tasks.isEmpty()) println("No tasks available."); for (task in tasks) { val status = if (task.isCompleted) "[X]" else "[ ]"; println("$status ${task.name}") } } fun completeTask(name: String) { val task = tasks.find { it.name == name }; if (task != null) { task.complete() } else { println("Task not found") } } fun clearCompleted() { val iterator = tasks.iterator(); while (iterator.hasNext()) { if (iterator.next().isCompleted) { iterator.remove() } }; println("Cleared completed tasks.") } } fun main() { println("Welcome to Task Manager"); val manager = TaskManager(); manager.addTask("Learn Kotlin"); manager.addTask("Write 15 commits"); manager.listTasks(); manager.completeTask("Learn Kotlin"); manager.listTasks(); manager.clearCompleted(); manager.listTasks() }
